            font-size: 0.65rem;
            cursor: pointer;
            transition: 0.1s;
        }
        .task-actions button:hover {
            background: #d9dce2;
        }

        /* ---- 模态框（新增/编辑） ---- */
        .modal-overlay {
            position: fixed;
            inset: 0;
            background: rgba(0,0,0,0.3);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 999;
            backdrop-filter: blur(2px);
        }
        .modal {
            background: white;
            max-width: 440px;
            width: 90%;
            padding: 1.8rem 1.5rem;
            border-radius: 24px;
            box-shadow: 0 16px 40px rgba(0,0,0,0.2);
            display: flex;
            flex-direction: column;
            gap: 1rem;
        }
        .modal h2 {
            font-size: 1.3rem;
            font-weight: 500;
        }
        .modal label {
            font-weight: 500;
            font-size: 0.85rem;
            display: flex;
            flex-direction: column;
            gap: 0.3rem;
        }
        .modal input, .modal textarea, .modal select {
            padding: 0.6rem 0.8rem;
