<body>
<div>
    <div class="aquarium-wrapper">
        <canvas id="aquariumCanvas" width="1000" height="600"></canvas>
    </div>
    <div class="info">
        <span>🐟 点击水面投放鱼食</span>
        <span>🎯 鱼会追逐最近的鱼食</span>
    </div>
</div>
<script>
    (function() {
        const canvas = document.getElementById('aquariumCanvas');
        const ctx = canvas.getContext('2d');
        const W = 1000, H = 600;

        // ----- 水体参数 (用于背景动画) -----
        let time = 0;

        // ----- 鱼群 -----
        const FISH_COUNT = 7;
        let fishes = [];

        // ----- 鱼食数组 -----
        let foodPellets = [];
        const MAX_FOOD = 22;          // 最多同时存在22粒
        const FOOD_RADIUS = 5;        // 视觉尺寸
        const EAT_DISTANCE = 12;      // 鱼吃掉食物的距离

        // ----- 鱼初始化 -----
        function createFish(id) {
            const hue = (id * 47 + 180) % 360;  // 从蓝绿到橙红
            // 随机大小 (1.0 ~ 2.2)
            const size = 1.0 + Math.random() * 1.2;
            // 游动参数
            return {
                id: id,
                x: Math.random() * (W - 80) + 40,
                y: Math.random() * (H - 80) + 40,
                vx: (Math.random() - 0.5) * 1.8,
                vy: (Math.random() - 0.5) * 1.2,
                size: size,
                hue: hue,
                // 用于自然摆动
                phase: Math.random() * Math.PI * 2,
                // 目标方向 (自由游动时缓慢变化)
                targetAngle: Math.random() * Math.PI * 2,
                turnTimer: 0,
                // 视觉闪烁
                glow: 0.7 + Math.random() * 0.3,
            };
        }

        function initFish() {
            fishes = [];
            for (let i = 0; i < FISH_COUNT; i++) {
                fishes.push(createFish(i));
            }
        }
        initFish();

        // ----- 鱼食管理 -----
        function addFood(x, y) {
            if (foodPellets.length >= MAX_FOOD) {
                // 移除最旧的一粒
                foodPellets.shift();
            }
            foodPellets.push({
                x: x,
                y: y,
                r: FOOD_RADIUS * (0.9 + Math.random() * 0.2),
                born: performance.now()
            });
        }

        // ----- 寻找最近的鱼食 (返回索引, 若没有返回 -1) -----
        function findNearestFood(fish) {
            let minDist = Infinity;
            let nearestIdx = -1;
            for (let i = 0; i < foodPellets.length; i++) {
                const dx = foodPellets[i].x - fish.x;
                const dy = foodPellets[i].y - fish.y;
                const dist = dx * dx + dy * dy;
                if (dist < minDist) {
                    minDist = dist;
                    nearestIdx = i;
                }
            }
            return nearestIdx;
        }

        // ----- 更新鱼群 (追逐 + 自由游动) -----
        function updateFish() {
            const boundaryMargin = 50;
            const turnSpeed = 0.018;
            const maxSpeed = 2.8;
            const chaseForce = 0.0075;    // 追逐加速度

            for (let f of fishes) {
                // 1. 判断是否有鱼食
                const nearestIdx = findNearestFood(f);
                let targetX = null, targetY = null;

                if (nearestIdx !== -1) {
                    const pellet = foodPellets[nearestIdx];
                    targetX = pellet.x;
                    targetY = pellet.y;
                }

                // 2. 计算加速度
                let accX = 0, accY = 0;

                if (targetX !== null) {
                    // 追逐模式
                    const dx = targetX - f.x;
                    const dy = targetY - f.y;
                    const dist = Math.hypot(dx, dy);
                    if (dist > 0.5) {
                        const normX = dx / dist;
                        const normY = dy / dist;
                        // 越靠近食物稍微减速，防止冲过头，但保持追逐
                        const speedFactor = Math.min(1.0, dist / 60);
                        accX = normX * chaseForce * speedFactor * 1.2;
                        accY = normY * chaseForce * speedFactor * 1.2;
                    }
                    // 额外轻微随机扰动，增加自然感
                    accX += (Math.random() - 0.5) * 0.0008;
                    accY += (Math.random() - 0.5) * 0.0008;
                } else {
                    // 自由游动：模拟悠闲转向
                    f.turnTimer += 0.005 + Math.random() * 0.01;
                    if (f.turnTimer > 0.6) {
                        f.targetAngle = Math.random() * Math.PI * 2;
                        f.turnTimer = 0;
                    }
                    // 当前角度
                    const currentAngle = Math.atan2(f.vy, f.vx);
                    let angleDiff = f.targetAngle - currentAngle;
                    // 规范化到 -PI ~ PI
                    while (angleDiff > Math.PI) angleDiff -= 2 * Math.PI;
                    while (angleDiff < -Math.PI) angleDiff += 2 * Math.PI;
                    const rotateForce = 0.0009;
                    accX += Math.cos(currentAngle + angleDiff * 0.1) * 0.02;
                    accY += Math.sin(currentAngle + angleDiff * 0.1) * 0.02;
                    // 增加柔和随机
                    accX += (Math.random() - 0.5) * 0.0025;
                    accY += (Math.random() - 0.5) * 0.0025;
                }

                // 3. 应用加速度
                f.vx += accX;
                f.vy += accY;

                // 4. 速度限制
                let speed = Math.hypot(f.vx, f.vy);
                if (speed > maxSpeed) {
                    f.vx = (f.vx / speed) * maxSpeed;
                    f.vy = (f.vy / speed) * maxSpeed;
                } else if (speed < 0.3 && targetX === null) {
                    // 自由游动时避免完全静止
                    f.vx += (Math.random() - 0.5) * 0.02;
                    f.vy += (Math.random() - 0.5) * 0.02;
                }

                // 5. 边界反弹 + 转向
                const margin = boundaryMargin;
                const bounceStrength = 0.4;
                if (f.x < margin) { f.vx += bounceStrength; f.x = margin + 2; }
                if (f.x > W - margin) { f.vx -= bounceStrength; f.x = W - margin - 2; }
                if (f.y < margin) { f.vy += bounceStrength; f.y = margin + 2; }
                if (f.y > H - margin) { f.vy -= bounceStrength; f.y = H - margin - 2; }

                // 额外边界柔和限制 (防止卡边界)
                f.x += f.vx;
                f.y += f.vy;

                // 硬边界 (完全防止越界)
                f.x = Math.min(Math.max(f.x, 10), W - 10);
                f.y = Math.min(Math.max(f.y, 10), H - 10);

                // 6. 更新相位 (尾巴摆动)
                f.phase += 0.06 + speed * 0.04;
            }
        }

        // ----- 鱼吃食物逻辑 -----
        function checkEatFood() {
            for (let f of fishes) {
                for (let i = foodPellets.length - 1; i >= 0; i--) {
                    const pellet = foodPellets[i];
                    const dx = f.x - pellet.x;
                    const dy = f.y - pellet.y;
                    const dist = Math.hypot(dx, dy);
                    if (dist < EAT_DISTANCE * (0.8 + f.size * 0.2)) {
                        // 吃掉
                        foodPellets.splice(i, 1);
                        break; // 一条鱼一帧最多吃一粒，跳出循环
                    }
                }
            }
        }

        // ----- 绘制水族箱 (背景 + 鱼 + 鱼食) -----
        function drawScene() {
            time += 0.003;
            // 清空
            ctx.clearRect(0, 0, W, H);

            // ----- 深海渐变背景 (带动态波纹) -----
            const grad = ctx.createRadialGradient(200, 180, 60, 400, 300, 800);
            grad.addColorStop(0, '#256b7c');
            grad.addColorStop(0.4, '#154c5e');
            grad.addColorStop(0.8, '#0b2d3a');
            grad.addColorStop(1, '#051a24');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, W, H);

            // 水纹 / 光柱 (动态)
            ctx.save();
            ctx.globalAlpha = 0.07;
            for (let i = 0; i < 5; i++) {
                const x = 120 + Math.sin(time * 0.5 + i * 2.3) * 80 + i * 60;
                const y = -20 + i * 30;
                ctx.beginPath();
                ctx.ellipse(x, y + Math.sin(time * 1.2 + i) * 10, 180 + Math.sin(time * 0.4 + i) * 30, 40 + Math.sin(time * 0.7 + i) * 15, 0, 0, Math.PI * 2);
                ctx.fillStyle = '#b7e4f0';
                ctx.fill();
            }
            ctx.restore();

            // 底部沙地光晕
            ctx.fillStyle = '#1b463d20';
            ctx.beginPath();
            ctx.rect(0, H-50, W, 50);
            ctx.fill();

            // ----- 绘制鱼食 (光晕 + 颗粒) -----
            for (let p of foodPellets) {
                const r = p.r || FOOD_RADIUS;
                // 发光
                const glow = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, r * 4);
                glow.addColorStop(0, '#fae0b0');
                glow.addColorStop(0.2, '#dba14a');
                glow.addColorStop(0.8, '#a1561a60');
                glow.addColorStop(1, '#00000000');
                ctx.beginPath();
                ctx.arc(p.x, p.y, r * 4, 0, 2 * Math.PI);
                ctx.fillStyle = glow;
                ctx.fill();

                // 食物核心
                ctx.beginPath();
                ctx.arc(p.x, p.y, r * 0.9, 0, 2 * Math.PI);
                ctx.fillStyle = '#f5c542';
                ctx.shadowColor = '#f5b142';
                ctx.shadowBlur = 18;
                ctx.fill();
                ctx.shadowBlur = 0;
                // 高光
                ctx.beginPath();
                ctx.arc(p.x - r*0.3, p.y - r*0.3, r*0.3, 0, 2 * Math.PI);
                ctx.fillStyle = '#ffeacc';
                ctx.fill();
            }

            // ----- 绘制鱼群 -----
            for (let f of fishes) {
                const angle = Math.atan2(f.vy, f.vx);
                const speed = Math.hypot(f.vx, f.vy);
                const bodyLength = 38 * f.size;
                const bodyHeight = 18 * f.size;
                const tailLen = 14 * f.size;

                ctx.save();
                ctx.translate(f.x, f.y);
                ctx.rotate(angle);

                // 鱼身光晕 (环境光)
                ctx.shadowColor = `hsla(${f.hue}, 70%, 60%, 0.3)`;
                ctx.shadowBlur = 22;

                // 身体 (椭圆)
                ctx.beginPath();
                ctx.ellipse(4, 0, bodyLength/2, bodyHeight/2, 0, 0, Math.PI * 2);
                // 主色 带渐变
                const gradient = ctx.createLinearGradient(-bodyLength/2, -bodyHeight/2, bodyLength/2, bodyHeight/2);
                gradient.addColorStop(0, `hsl(${f.hue}, 75%, 55%)`);
                gradient.addColorStop(0.6, `hsl(${f.hue + 15}, 80%, 70%)`);
                gradient.addColorStop(1, `hsl(${f.hue + 30}, 70%, 50%)`);
                ctx.fillStyle = gradient;
                ctx.fill();
                ctx.shadowBlur = 0;

                // 腹部亮纹
                ctx.beginPath();
                ctx.ellipse(0, 4, bodyLength/2.5, bodyHeight/5, 0, 0, Math.PI * 2);
                ctx.fillStyle = `hsla(${f.hue + 40}, 60%, 85%, 0.4)`;
                ctx.fill();

                // 尾巴 (随相位摆动)
                const tailWag = Math.sin(f.phase) * 0.25 + 0.1;
                ctx.beginPath();
                ctx.moveTo(-bodyLength/2 + 2, 0);
                ctx.lineTo(-bodyLength/2 - tailLen, -bodyHeight/2.5 - tailWag * 8);
                ctx.lineTo(-bodyLength/2 - tailLen, bodyHeight/2.5 + tailWag * 8);
                ctx.closePath();
                ctx.fillStyle = `hsl(${f.hue + 10}, 65%, 45%)`;
                ctx.fill();

                // 眼睛
                ctx.beginPath();
                ctx.arc(bodyLength/4.5, -bodyHeight/6, 3.2 * f.size, 0, 2 * Math.PI);
                ctx.fillStyle = '#fcf9f2';
                ctx.fill();
                ctx.beginPath();
                ctx.arc(bodyLength/4.5 + 1.2, -bodyHeight/6 - 0.5, 1.6 * f.size, 0, 2 * Math.PI);
                ctx.fillStyle = '#1d2b33';
                ctx.fill();
                // 眼神光
                ctx.beginPath();
                ctx.arc(bodyLength/4.5 + 2.4, -bodyHeight/6 - 1.8, 0.8 * f.size, 0, 2 * Math.PI);
                ctx.fillStyle = 'white';
                ctx.fill();

                // 背鳍 (小)
                ctx.beginPath();
                ctx.moveTo(6, -bodyHeight/2.2);
                ctx.lineTo(12, -bodyHeight/1.6);
                ctx.lineTo(18, -bodyHeight/2.4);
                ctx.fillStyle = `hsl(${f.hue + 25}, 60%, 50%)`;
                ctx.globalAlpha = 0.7;
                ctx.fill();
                ctx.globalAlpha = 1.0;

                ctx.restore();
            }

            // 水面高光 (环境)
            ctx.save();
            ctx.globalAlpha = 0.06 + Math.sin(time * 0.8) * 0.02;
            for (let i = 0; i < 12; i++) {
                const x = (i * 90 + time * 20) % (W + 100) - 50;
                const y = 10 + Math.sin(i * 1.5 + time * 1.7) * 18;
                ctx.beginPath();
                ctx.ellipse(x, y, 30 + Math.sin(i + time) * 8, 4, 0, 0, Math.PI * 2);
                ctx.fillStyle = '#d2ecf5';
                ctx.fill();
            }
            ctx.restore();

            // 角落水草 (装饰)
            ctx.save();
            ctx.shadowBlur = 20;
            ctx.shadowColor = '#0b3a2a';
            for (let i = 0; i < 3; i++) {
                const baseX = 30 + i * 45;
                const baseY = H - 20;
                ctx.beginPath();
                ctx.moveTo(baseX, baseY);
                ctx.quadraticCurveTo(baseX - 18 + Math.sin(time * 1.2 + i) * 6, baseY - 80 - i*10, baseX + Math.sin(time * 0.9 + i) * 10, baseY - 120 - i*15);
                ctx.lineWidth = 8 + i * 2;
                ctx.strokeStyle = `#1f6b4a`;
                ctx.lineCap = 'round';
                ctx.stroke();
            }
            ctx.restore();
        }

        // ----- 动画循环 -----
        function animate() {
            updateFish();
            checkEatFood();
            drawScene();
            requestAnimationFrame(animate);
        }

        // ----- 鼠标/触控 投放鱼食 -----
        function handleFeed(e) {
            const rect = canvas.getBoundingClientRect();
            const scaleX = canvas.width / rect.width;
            const scaleY = canvas.height / rect.height;
            let clientX, clientY;

            if (e.touches) {
                clientX = e.touches[0].clientX;
                clientY = e.touches[0].clientY;
                e.preventDefault();
            } else {
                clientX = e.clientX;
                clientY = e.clientY;
            }

            const canvasX = (clientX - rect.left) * scaleX;
            const canvasY = (clientY - rect.top) * scaleY;

            if (canvasX >= 0 && canvasX <= W && canvasY >= 0 && canvasY <= H) {
                addFood(canvasX, canvasY);
            }
        }

        // ----- 事件绑定 (鼠标+触控) -----
        canvas.addEventListener('mousedown', handleFeed);
        canvas.addEventListener('touchstart', handleFeed, { passive: false });

        // 窗口大小变化不重置，仅自适应显示 (canvas不变)
        // 启动动画
        animate();

        // 额外: 点击时轻微视觉反馈 (通过css active已完成)
    })();
</script>
</body>
</html>
```
### 水族箱玩法与交互机制

您可以点击水面投放鱼食，观察鱼群的自然游动与觅食行为。其核心逻辑围绕鱼类的两种状态切换展开。

-   **点击喂食与鱼群追逐**：在水族箱任意位置点击，即可投放一粒发光的鱼食。每条鱼会实时计算并追逐离自己最近的那一粒，接近到一定距离后便会“吃掉”它。
-   **自然的游动模拟**：当没有鱼食时，每条鱼会进入“自由游动”模式，其游动方向会随机且柔和地变化，并伴有身体摆动和尾部摇曳的动画，显得生动自然。
-   **丰富的视觉细节**：鱼身色彩、大小各异，并带有渐变光泽和动态高光。背景含有缓慢飘动的光柱和摇曳的水草，营造出沉浸的水下氛围。

以下是您需要的单文件HTML时钟应用，它是一款具有高级感视觉风格的圆形时钟，并显示中国标准时间。
```html
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>高级感 · 北京时区时钟</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }
        body {
            min-height: 100vh;
            background: #f5f7fa;
            display: flex;
            justify-content: center;
            align-items: center;
            font-family: 'Segoe UI', 'PingFang SC', Roboto, system-ui, -apple-system, sans-serif;
            padding: 20px;
        }
        .clock-wrapper {
            background: white;
            border-radius: 50%;
            box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08), 0 8px 20px rgba(0, 0, 0, 0.06), 0 0 0 1px rgba(0, 0, 0, 0.02);
            padding: 20px;
            transition: box-shadow 0.2s;
        }
        .clock-wrapper:hover {
            box-shadow: 0 28px 48px rgba(0, 0, 0, 0.10), 0 10px 24px rgba(0, 0, 0, 0.08), 0 0 0 1px rgba(0, 0, 0, 0.02);
        }
        canvas {
            display: block;
            width: 360px;
            height: 360px;
            border-radius: 50%;
            background: white;
            box-shadow: inset 0 4px 8px rgba(0,0,0,0.02), 0 0 0 2px #eaeef2, 0 6px 14px rgba(0,0,0,0.04);
            transition: box-shadow 0.2s;
        }
        /* 移动端自适应 */
        @media (max-width: 420px) {
            canvas {
                width: 280px;
                height: 280px;
            }
            .clock-wrapper {
                padding: 14px;
            }
        }
    </style>
</head>
<body>
<div class="clock-wrapper">
    <canvas id="clockCanvas" width="600" height="600"></canvas>
</div>
<script>
    (function() {
        const canvas = document.getElementById('clockCanvas');
        const ctx = canvas.getContext('2d');

        // 尺寸常量 (基于 canvas 逻辑尺寸 600x600)
        const SIZE = 600;
        const CENTER = SIZE / 2;
        const RADIUS = 270;          // 表盘半径
        const OUTER_R = 282;         // 外圈轻微阴影边界

        // 北京时区 ( Asia/Shanghai )
        const TIMEZONE = 'Asia/Shanghai';

        // 预先计算 60 个刻度的角度 (0 ~ 59)  角度以弧度存储，并处理起始点 12点钟方向 (-90°)
        const tickAngles = new Array(60);
        for (let i = 0; i < 60; i++) {
            // 每个刻度间隔 6°, 但起始偏移 -90° (使0分钟指向12点)
            tickAngles[i] = (i * 6 - 90) * Math.PI / 180;
        }

        // 整点刻度索引 (0, 5, 10, 15, 20, 25, 30, 35, 40, 45, 50, 55)
        const hourTickIndexes = [];
        for (let i = 0; i < 60; i += 5) {
            hourTickIndexes.push(i);
        }
        const hourTickSet = new Set(hourTickIndexes);

        // ----------------------------------------------
        // 绘制静态表盘：刻度、数字、外圈修饰
        // 为了性能，只绘制一次 (但秒针平滑运动时，背景不变)
        // 但为了时针/分针/秒针重绘，我们仍然需要每帧重绘整个canvas
        // 因此 drawStaticPart 会被每帧调用，但纯canvas操作很快。
        // 为了代码清晰，不采用离屏canvas。
        // ----------------------------------------------
        function drawStaticPart() {
            // ------- 外圈柔和阴影 (先画一个半透明环，增加3D层次) -------
            ctx.save();

            // 1. 外圈精细 3D 阴影 (发光/暗边)
            ctx.beginPath();
            ctx.arc(CENTER, CENTER, OUTER_R, 0, 2 * Math.PI);
            ctx.shadowColor = 'rgba(0,0,0,0.08)';
            ctx.shadowBlur = 16;
            ctx.shadowOffsetX = 2;
            ctx.shadowOffsetY = 4;
            ctx.fillStyle = '#ffffff';
            ctx.fill();

            // 清除阴影避免干扰后续绘制
            ctx.shadowColor = 'transparent';
            ctx.shadowBlur = 0;
            ctx.shadowOffsetX = 0;
            ctx.shadowOffsetY = 0;

            // 2. 主表盘背景(纯白) + 深色极细边框
            ctx.beginPath();
            ctx.arc(CENTER, CENTER, RADIUS, 0, 2 * Math.PI);
            ctx.fillStyle = '#ffffff';
            ctx.fill();
            ctx.strokeStyle = '#1e2a36';
            ctx.lineWidth = 3;
            ctx.stroke();

            // 3. 内圈浅灰色装饰细环 (提升质感)
            ctx.beginPath();
            ctx.arc(CENTER, CENTER, RADIUS - 12, 0, 2 * Math.PI);
            ctx.strokeStyle = '#dce3e9';
            ctx.lineWidth = 1.2;
            ctx.stroke();

            // ------- 绘制 60 个刻度 (整点加粗) -------
            for (let i = 0; i < 60; i++) {
                const angle = tickAngles[i];
                // 内侧半径 (整点刻度的内径稍小，显得更长)
                let innerR = RADIUS - 32;
                let outerR = RADIUS - 12;
                let lineWidth = 2.2;
                let color = '#33475b';

                if (hourTickSet.has(i)) {
                    // 整点刻度：更粗、更长、更深
                    innerR = RADIUS - 42;
                    outerR = RADIUS - 12;
                    lineWidth = 4.2;
                    color = '#121c26';
                } else {
                    // 非整点刻度：细一些，颜色浅一点
                    lineWidth = 1.8;
                    color = '#5c6f82';
                }

                const cosA = Math.cos(angle);
                const sinA = Math.sin(angle);

                const x1 = CENTER + innerR * cosA;
                const y1 = CENTER + innerR * sinA;
                const x2 = CENTER + outerR * cosA;
                const y2 = CENTER + outerR * sinA;

                ctx.beginPath();
                ctx.moveTo(x1, y1);
                ctx.lineTo(x2, y2);
                ctx.strokeStyle = color;
                ctx.lineWidth = lineWidth;
                ctx.lineCap = 'round';
                ctx.stroke();
            }

            // ------- 绘制数字 (1~12) -------
            ctx.fillStyle = '#14222e';
            ctx.font = '500 38px "Segoe UI", "PingFang SC", Roboto, Helvetica, Arial, sans-serif';
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            // 数字距离圆心稍微远一点，但不要太靠边缘
            const numRadius = RADIUS - 56;

            for (let i = 1; i <= 12; i++) {
                // 角度: 每个数字间隔30°, 从12点 ( -90° ) 开始
                const angle = (i * 30 - 90) * Math.PI / 180;
                const x = CENTER + numRadius * Math.cos(angle);
                const y = CENTER + numRadius * Math.sin(angle);
                ctx.fillStyle = '#14222e';
                ctx.shadowColor = 'rgba(0,0,0,0.02)';
                ctx.shadowBlur = 2;
                ctx.fillText(String(i), x, y);
                ctx.shadowColor = 'transparent';
                ctx.shadowBlur = 0;
            }

            // ------- 中心小圆点 (装饰) -------
            ctx.beginPath();
            ctx.arc(CENTER, CENTER, 8, 0, 2 * Math.PI);
            ctx.fillStyle = '#1e2a36';
            ctx.shadowColor = 'rgba(0,0,0,0.08)';
            ctx.shadowBlur = 6;
            ctx.fill();
            ctx.shadowColor = 'transparent';
            ctx.shadowBlur = 0;

            // 内部更小的点 (增加层次)
            ctx.beginPath();
            ctx.arc(CENTER, CENTER, 3.5, 0, 2 * Math.PI);
            ctx.fillStyle = '#ffffff';
            ctx.fill();

            ctx.restore();
        }

        // ----------------------------------------------
        // 更新指针 (根据当前北京时区时间)
        // 秒针平滑：使用毫秒计算微角度
        // ----------------------------------------------
        function updateClock() {
            // 获取北京时区时间
            const now = new Date();
            // 使用 Intl.DateTimeFormat 或直接 toLocaleString 获取北京时区字符串再解析
            // 更精准方法: 计算 UTC + 8
            // 注意: 浏览器可能不支持Asia/Shanghai时区？但主流Edge/Chrome/Firefox均支持。
            let beijingTime;
            try {
                const options = {
                    timeZone: TIMEZONE,
                    hour: '2-digit',
                    minute: '2-digit',
                    second: '2-digit',
                    hour12: false,
                    year: 'numeric',
                    month: '2-digit',
                    day: '2-digit',
                };
                const formatter = new Intl.DateTimeFormat('zh-CN', options);
                const parts = formatter.formatToParts(now);
                // 解析 parts
                let year = '', month = '', day = '', hour = '', minute = '', second = '';
                for (const part of parts) {
                    switch (part.type) {
                        case 'year': year = part.value; break;
                        case 'month': month = part.value; break;
                        case 'day': day = part.value; break;
                        case 'hour': hour = part.value; break;
                        case 'minute': minute = part.value; break;
                        case 'second': second = part.value; break;
                    }
                }
                // 组合成 Date 对象 (基于北京时区)
                // 为避免解析误差，直接用 UTC 偏移计算
                // 但上面方法在大部分现代浏览器可靠，作为备选，我们再用偏移量确保
                // 方法更稳健：直接计算 UTC+8
                const utc = now.getTime() + now.getTimezoneOffset() * 60000;
                const beijingOffset = 8 * 60 * 60000;
                const beijingDate = new Date(utc + beijingOffset);

                // 但如果上面Intl解析成功，也可以直接使用，不过为了统一，使用 beijingDate
                // 同时保留日期变量
                const bjHours = beijingDate.getUTCHours();
                const bjMinutes = beijingDate.getUTCMinutes();
                const bjSeconds = beijingDate.getUTCSeconds();
                const bjMilliseconds = beijingDate.getUTCMilliseconds();

                // 日期字符串 (从 beijingDate 获取)
                const bjYear = beijingDate.getUTCFullYear();
                const bjMonth = String(beijingDate.getUTCMonth() + 1).padStart(2, '0');
                const bjDay = String(beijingDate.getUTCDate()).padStart(2, '0');

                // 计算指针角度 (弧度)
                // 秒针: 平滑 (包含毫秒)
                const smoothSeconds = bjSeconds + bjMilliseconds / 1000;
                const secondAngle = (smoothSeconds / 60) * 2 * Math.PI - Math.PI / 2;

                // 分针: 每分钟6°, 加上秒针微调 (0.1° 每秒)
                const minuteAngle = (bjMinutes / 60) * 2 * Math.PI - Math.PI / 2 + (bjSeconds / 60) * (2 * Math.PI / 60);

                // 时针: 每小时30°, 加上分钟微调
                const hourAngle = (bjHours % 12) / 12 * 2 * Math.PI - Math.PI / 2 + (bjMinutes / 60) * (2 * Math.PI / 12);

                // 清空画布 (但背景重绘静态部分)
                ctx.clearRect(0, 0, SIZE, SIZE);

                // 1. 绘制静态表盘 (刻度、数字、外圈)
                drawStaticPart();

                // 2. 绘制时针 (深色, 宽)
                ctx.save();
                ctx.shadowColor = 'rgba(0,0,0,0.08)';
                ctx.shadowBlur = 10;
                ctx.shadowOffsetX = 2;
                ctx.shadowOffsetY = 4;
                ctx.beginPath();
                ctx.moveTo(CENTER, CENTER);
                const hourLen = RADIUS * 0.45;
                ctx.lineTo(CENTER + hourLen * Math.cos(hourAngle), CENTER + hourLen * Math.sin(hourAngle));
                ctx.strokeStyle = '#14222e';
                ctx.lineWidth = 8;
                ctx.lineCap = 'round';
                ctx.stroke();

                // 3. 分针 (稍浅, 细)
                ctx.beginPath();
                ctx.moveTo(CENTER, CENTER);
                const minLen = RADIUS * 0.62;
                ctx.lineTo(CENTER + minLen * Math.cos(minuteAngle), CENTER + minLen * Math.sin(minuteAngle));
                ctx.strokeStyle = '#2b3e50';
                ctx.lineWidth = 5.5;
                ctx.lineCap = 'round';
                ctx.stroke();

                // 4. 秒针 (亮色 / 红色或蓝灰, 细长)
                ctx.beginPath();
                ctx.moveTo(CENTER, CENTER);
                const secLen = RADIUS * 0.70;
                ctx.lineTo(CENTER + secLen * Math.cos(secondAngle), CENTER + secLen * Math.sin(secondAngle));
                ctx.strokeStyle = '#c0392b';
                ctx.lineWidth = 2.6;
                ctx.lineCap = 'round';
                ctx.stroke();

                // 秒针尾部小平衡 (细) – 增加高级感
                ctx.beginPath();
                const tailLen = 24;
                ctx.moveTo(CENTER - tailLen * Math.cos(secondAngle), CENTER - tailLen * Math.sin(secondAngle));
                ctx.lineTo(CENTER, CENTER);
                ctx.strokeStyle = '#c0392b';
                ctx.lineWidth = 2;
                ctx.lineCap = 'round';
                ctx.stroke();

                ctx.restore();

                // 5. 中心红点 (覆盖指针根部)
                ctx.beginPath();
                ctx.arc(CENTER, CENTER, 6, 0, 2 * Math.PI);
                ctx.fillStyle = '#c0392b';
                ctx.shadowColor = 'rgba(0,0,0,0.1)';
                ctx.shadowBlur = 6;
                ctx.fill();
                ctx.shadowColor = 'transparent';
                ctx.shadowBlur = 0;
                ctx.beginPath();
                ctx.arc(CENTER, CENTER, 2.5, 0, 2 * Math.PI);
                ctx.fillStyle = '#f5f7fa';
                ctx.fill();

                // 6. 在表盘内部显示当前日期和时间 (北京时区)
                ctx.fillStyle = '#1e2a36';
                ctx.font = '500 22px "Segoe UI", "PingFang SC", Roboto, sans-serif';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                // 放在圆心下方约 65px 处
                const dateY = CENTER + 78;
                const timeY = CENTER + 108;
                ctx.fillStyle = '#3f5568';
                ctx.font = '460 20px "Segoe UI", "PingFang SC", Roboto, sans-serif';
                ctx.fillText(`${bjYear}-${bjMonth}-${bjDay}`, CENTER, dateY);
                ctx.font = '500 28px "Segoe UI", "PingFang SC", Roboto, sans-serif';
                ctx.fillStyle = '#14222e';
                const timeStr = `${String(bjHours).padStart(2, '0')}:${String(bjMinutes).padStart(2, '0')}:${String(bjSeconds).padStart(2, '0')}`;
                ctx.fillText(timeStr, CENTER, timeY);

            } catch (e) {
                // 降级方案：如果浏览器不支持 Asia/Shanghai，回退至 UTC+8 手动计算
                console.warn('时区解析回退至 UTC+8', e);
                const now = new Date();
                const utc = now.getTime() + now.getTimezoneOffset() * 60000;
                const beijingOffset = 8 * 60 * 60000;
                const beijingDate = new Date(utc + beijingOffset);

                const bjHours = beijingDate.getUTCHours();
                const bjMinutes = beijingDate.getUTCMinutes();
                const bjSeconds = beijingDate.getUTCSeconds();
                const bjMilliseconds = beijingDate.getUTCMilliseconds();

                const smoothSeconds = bjSeconds + bjMilliseconds / 1000;
                const secondAngle = (smoothSeconds / 60) * 2 * Math.PI - Math.PI / 2;
                const minuteAngle = (bjMinutes / 60) * 2 * Math.PI - Math.PI / 2 + (bjSeconds / 60) * (2 * Math.PI / 60);
                const hourAngle = (bjHours % 12) / 12 * 2 * Math.PI - Math.PI / 2 + (bjMinutes / 60) * (2 * Math.PI / 12);

                ctx.clearRect(0, 0, SIZE, SIZE);
                drawStaticPart();

                // 时针
                ctx.save();
                ctx.shadowColor = 'rgba(0,0,0,0.08)'; ctx.shadowBlur = 10; ctx.shadowOffsetX = 2; ctx.shadowOffsetY = 4;
                ctx.beginPath(); ctx.moveTo(CENTER, CENTER);
                ctx.lineTo(CENTER + RADIUS*0.45 * Math.cos(hourAngle), CENTER + RADIUS*0.45 * Math.sin(hourAngle));
                ctx.strokeStyle = '#14222e'; ctx.lineWidth = 8; ctx.lineCap = 'round'; ctx.stroke();
                // 分针
                ctx.beginPath(); ctx.moveTo(CENTER, CENTER);
                ctx.lineTo(CENTER + RADIUS*0.62 * Math.cos(minuteAngle), CENTER + RADIUS*0.62 * Math.sin(minuteAngle));
                ctx.strokeStyle = '#2b3e50'; ctx.lineWidth = 5.5; ctx.lineCap = 'round'; ctx.stroke();
                // 秒针
                ctx.beginPath(); ctx.moveTo(CENTER, CENTER);
                ctx.lineTo(CENTER + RADIUS*0.70 * Math.cos(secondAngle), CENTER + RADIUS*0.70 * Math.sin(secondAngle));
                ctx.strokeStyle = '#c0392b'; ctx.lineWidth = 2.6; ctx.lineCap = 'round'; ctx.stroke();
                ctx.beginPath();
                ctx.moveTo(CENTER - 24 * Math.cos(secondAngle), CENTER - 24 * Math.sin(secondAngle));
                ctx.lineTo(CENTER, CENTER);
                ctx.strokeStyle = '#c0392b'; ctx.lineWidth = 2; ctx.lineCap = 'round'; ctx.stroke();
                ctx.restore();

                ctx.beginPath(); ctx.arc(CENTER, CENTER, 6, 0, 2*Math.PI); ctx.fillStyle = '#c0392b'; ctx.shadowBlur=6; ctx.shadowColor='rgba(0,0,0,0.1)'; ctx.fill(); ctx.shadowColor='transparent';
                ctx.beginPath(); ctx.arc(CENTER, CENTER, 2.5, 0, 2*Math.PI); ctx.fillStyle = '#f5f7fa'; ctx.fill();

                const bjYear = beijingDate.getUTCFullYear();
                const bjMonth = String(beijingDate.getUTCMonth()+1).padStart(2,'0');
                const bjDay = String(beijingDate.getUTCDate()).padStart(2,'0');
                const bjH = String(bjHours).padStart(2,'0');
                const bjM = String(bjMinutes).padStart(2,'0');
                const bjS = String(bjSeconds).padStart(2,'0');
                ctx.fillStyle = '#3f5568'; ctx.font = '460 20px "Segoe UI", "PingFang SC", Roboto, sans-serif';
                ctx.fillText(`${bjYear}-${bjMonth}-${bjDay}`, CENTER, CENTER+78);
                ctx.fillStyle = '#14222e'; ctx.font = '500 28px "Segoe UI", "PingFang SC", Roboto, sans-serif';
                ctx.fillText(`${bjH}:${bjM}:${bjS}`, CENTER, CENTER+108);
            }
        }

        // 使用 requestAnimationFrame 实现平滑动画
        let animationId = null;
        function animate() {
            updateClock();
            animationId = requestAnimationFrame(animate);
        }

        // 启动动画
        animate();

        // 清理动画 (页面卸载时)
        window.addEventListener('beforeunload', function() {
            if (animationId) {
                cancelAnimationFrame(animationId);
                animationId = null;
            }
        });

        // 边缘兼容: 如果浏览器不支持 requestAnimationFrame, 降级至 setInterval
        if (typeof requestAnimationFrame !== 'function') {
            console.log('requestAnimationFrame 不支持，降级至 setInterval');
            if (animationId) cancelAnimationFrame(animationId);
            setInterval(function() {
                updateClock();
            }, 50); // 50ms ≈ 20fps，但秒针依然平滑
        }
    })();
</script>
</body>
</html>
```
### 时钟功能与视觉设计
您可以通过这个清晰的模拟时钟，直观地获取当前时间。它的指针运动平滑，并整合了日期显示。
-   **时间显示与更新**：时钟核心通过 `updateClock()` 函数获取北京时区时间，并计算时针、分针和秒针的角度。秒针实现了平滑运动，而非传统的“滴答”跳动。
-   **表盘与刻度**：表盘为圆形，使用 CSS 和 Canvas 绘制。60 个刻度由 JavaScript 动态生成，其中整点刻度被设计得更粗、颜色更深，便于快速辨识。
-   **视觉风格与交互**：整体采用白色背景、深色边框和细微的 3D 阴影，营造简洁高级感。表盘内部会同步显示当前的数字日期和时间。

