            font-family: 'Segoe UI', 'Roboto', system-ui, -apple-system, sans-serif;
        }

        /* ---------- CLOCK CONTAINER ---------- */
        .clock-dial {
            position: relative;
            width: 360px;
            height: 360px;
            border-radius: 50%;
            background: #fcfcfc;
            box-shadow: 
                0 20px 30px rgba(0, 0, 0, 0.15),
                0 8px 12px rgba(0, 0, 0, 0.05),
                inset 0 -4px 8px rgba(0,0,0,0.02),
                inset 0 4px 8px rgba(255,255,255,0.7);
            border: 2px solid rgba(30, 30, 30, 0.25);
            /* subtle inner glow */
            transition: box-shadow 0.1s;
        }

        /* ---------- SCALES (60 ticks) ---------- */
        .scales-layer {
            position: absolute;
            width: 100%;
            height: 100%;
            top: 0;
            left: 0;
            border-radius: 50%;
        }

        .tick {
            position: absolute;
            bottom: 50%;
            left: 50%;
            width: 2px;
            height: 12px;
            background: #b0b8c0;
            transform-origin: bottom center;
            border-radius: 1px;
            pointer-events: none;
        }

        .tick.thick {
            width: 3px;
            height: 20px;
            background: #2d3238;
            margin-left: -1.5px;
            opacity: 0.9;
        }

        .tick.thin {
            width: 1.5px;
            height: 8px;
            background: #c4cad2;
            margin-left: -0.75px;
            opacity: 0.6;
        }

        /* ---------- NUMBERS (12h) ---------- */
        .numbers-layer {
            position: absolute;
            width: 100%;
            height: 100%;
            top: 0;
            left: 0;
            border-radius: 50%;
        }

        .number {
            position: absolute;
            font-size: 22px;
            font-weight: 500;
            color: #24292e;
            letter-spacing: 0.5px;
            width: 30px;
            height: 30px;
            display: flex;
            align-items: center;
            justify-content: center;
            transform-origin: center center;
            pointer-events: none;
            font-family: 'Segoe UI', 'Roboto', sans-serif;
        }

        /* ---------- HANDS ---------- */
        .hand {
            position: absolute;
            bottom: 50%;
            left: 50%;
            transform-origin: bottom center;
            border-radius: 8px;
            pointer-events: none;
            transition: none;
        }

        .hour-hand {
            width: 6px;
            height: 85px;
            margin-left: -3px;
            background: #1e2228;
            box-shadow: 0 2px 6px rgba(0,0,0,0.2);
            border-radius: 6px;
            z-index: 10;
        }

        .minute-hand {
            width: 4px;
            height: 125px;
            margin-left: -2px;
            background: #262c34;
            box-shadow: 0 2px 5px rgba(0,0,0,0.15);
