            z-index: 11;
        }

        .second-hand {
            width: 2px;
            height: 140px;
            margin-left: -1px;
            background: #d9434e;
            border-radius: 4px;
            z-index: 12;
            box-shadow: 0 0 6px rgba(217, 67, 78, 0.25);
            transition: none;
        }

        /* tiny center dot */
        .center-dot {
            position: absolute;
            top: 50%;
            left: 50%;
            width: 12px;
            height: 12px;
            transform: translate(-50%, -50%);
            background: #262c34;
            border-radius: 50%;
            z-index: 20;
            border: 2px solid #f5f7fa;
            box-shadow: 0 0 4px rgba(0,0,0,0.08);
        }

        /* ---------- TEXT INFO (upper / lower) ---------- */
        .text-info {
            position: absolute;
            left: 0;
            width: 100%;
            pointer-events: none;
            text-align: center;
            font-family: 'Segoe UI', 'Roboto', sans-serif;
