<!-- MODAL (hidden by default) -->
<div id="modalContainer" class="modal-overlay" role="dialog" aria-modal="true" aria-labelledby="modalTitle" style="display:none;">
    <div class="modal">
        <h2 id="modalTitle">New Note</h2>
