      display: flex;
      align-items: center;
      justify-content: center;
      transition: box-shadow 0.1s;
    }

    /* scale wrapper: 60 lines generated by JS */
    .scales-container {
      position: absolute;
      width: 100%;
      height: 100%;
      top: 0;
      left: 0;
      border-radius: 50%;
      overflow: hidden; /* keep sharp edges */
