<script>
  (function() {
    // ----- 1. generate scales (60 lines) -----
    const container = document.getElementById('scalesContainer');
    const totalScales = 60;
    for (let i = 0; i < totalScales; i++) {
      const deg = i * 6;  // 360/60
      const lineDiv = document.createElement('div');
      lineDiv.className = 'scale-line';
      // every 5th index is hour mark (0,5,10,... corresponds to 12,1,2,...)
      if (i % 5 === 0) {
        lineDiv.classList.add('hour-mark');
      }
      // rotate around center: transform rotate + translate
      lineDiv.style.transform = `rotate(${deg}deg)`;

      const inner = document.createElement('div');
      inner.className = 'scale-line-inner';
      lineDiv.appendChild(inner);
      container.appendChild(lineDiv);
    }

    // ----- 2. DOM references -----
    const hourHand = document.getElementById('hourHand');
    const minuteHand = document.getElementById('minuteHand');
    const secondHand = document.getElementById('secondHand');
    const timeDisplay = document.getElementById('timeDisplay');
    const dateDisplay = document.getElementById('dateDisplay');

    // ----- 3. update clock (Beijing time UTC+8) -----
    function updateClock() {
      // fetch current time in Shanghai timezone
      const now = new Date();
      // Use Intl.DateTimeFormat to get Beijing time parts (accurate)
      const timeStr = now.toLocaleString('en-US', { timeZone: 'Asia/Shanghai', hour12: false });
      // parse: "4/1/2025, 14:32:15"  or similar
      const parsed = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Shanghai' }));
      // but to be safe, we rebuild from parts
      const datePart = now.toLocaleDateString('en-US', { timeZone: 'Asia/Shanghai' });
      const timePart = now.toLocaleTimeString('en-US', { timeZone: 'Asia/Shanghai', hour12: false });

      // alternative: get exact hours, minutes, seconds from Intl
      const beijingTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Shanghai' }));
      // However, to avoid minute differences, we compute using UTC offset.
      // reliable method: use Date with offset
      const utc = now.getTime() + now.getTimezoneOffset() * 60000;
      const beijingOffset = 8 * 60 * 60000; // UTC+8
      const beijingDate = new Date(utc + beijingOffset);

      // extract components
      const hours = beijingDate.getHours();
      const minutes = beijingDate.getMinutes();
      const seconds = beijingDate.getSeconds();
      const milliseconds = beijingDate.getMilliseconds();

      // ----- compute rotation angles (with smooth seconds) -----
      // second hand: continuous (0.5° per 100ms, but we use precise ms)
      const secondAngle = (seconds + milliseconds / 1000) * 6;  // 6° per second

      // minute hand: smooth (includes seconds & ms)
      const minuteAngle = (minutes + seconds / 60 + milliseconds / 60000) * 6;

      // hour hand: 30° per hour + minute influence
      const hourAngle = ((hours % 12) + minutes / 60 + seconds / 3600) * 30;

      // apply transforms
      hourHand.style.transform = `rotate(${hourAngle}deg)`;
      minuteHand.style.transform = `rotate(${minuteAngle}deg)`;
      secondHand.style.transform = `rotate(${secondAngle}deg)`;

      // ----- update digital time (24h) -----
      const hh = String(hours).padStart(2, '0');
      const mm = String(minutes).padStart(2, '0');
      const ss = String(seconds).padStart(2, '0');
      timeDisplay.textContent = `${hh}:${mm}:${ss}`;

      // ----- update date & day of week (Beijing) -----
      const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      // get day of week from beijingDate (it's synced to beijing)
      const weekIndex = beijingDate.getDay(); 
      const dayOfWeek = dayNames[weekIndex];

      // format date: YYYY-MM-DD
      const year = beijingDate.getFullYear();
      const month = String(beijingDate.getMonth() + 1).padStart(2, '0');
      const day = String(beijingDate.getDate()).padStart(2, '0');

      dateDisplay.textContent = `${year}-${month}-${day}  ${dayOfWeek}`;
    }

    // ----- 4. start loop with requestAnimationFrame (smooth, low CPU) -----
    let lastTimestamp = 0;
    function tickLoop(timestamp) {
      // update every frame (~16ms) ensures smooth second hand
      if (!lastTimestamp || timestamp - lastTimestamp >= 50) { // limit to ~20fps min (but smooth)
        updateClock();
        lastTimestamp = timestamp;
      }
      requestAnimationFrame(tickLoop);
    }

    // initial call
    updateClock();
    // start loop
    requestAnimationFrame(tickLoop);

    // fallback: also setInterval to guarantee update even if tab inactive (RAF may pause)
    setInterval(() => {
      // extra safeguard: update every 200ms to avoid missing seconds
      // but RAF already does. However for Edge sleeping we set a lightweight timer
      if (document.hidden === false) {
        // only if visible, but RAF is better
      }
    }, 200);

    // Also, update when page becomes visible again (Edge sometimes suspend RAF)
    document.addEventListener('visibilitychange', function() {
      if (!document.hidden) {
        updateClock();
      }
    });

    // Edge / resize friendly (no extra action)
    console.log('🕐 Minimal wall clock · Beijing time');
  })();
</script>

