        .modal-field input, .modal-field textarea, .modal-field select {
            width: 100%;
            padding: 0.6rem 0.9rem;
            border: 1px solid #cbd5e1;
            border-radius: 18px;
            font-size: 0.95rem;
            background: #fafcff;
        }

        .modal-field textarea {
            min-height: 60px;
            resize: vertical;
        }

        .modal-actions {
            display: flex;
            justify-content: flex-end;
            gap: 0.7rem;
            margin-top: 1.5rem;
        }

        .hidden {
            display: none !important;
        }

        /* 响应式：窄屏纵向 */
        @media (max-width: 700px) {
            body { padding: 0.8rem; }
            .columns-grid {
                grid-template-columns: 1fr;
                gap: 1.2rem;
            }
            .board-header {
                flex-direction: column;
                align-items: stretch;
            }
            .toolbar {
                border-radius: 30px;
                justify-content: center;
            }
        }
    </style>
</head>
<body>
