<!-- 模态框：新增／编辑 (共用) -->
<div id="taskModal" class="modal-overlay hidden" role="dialog" aria-modal="true" aria-labelledby="modalTitle">
    <div class="modal-box">
        <h2 id="modalTitle">新建任务</h2>
