      const beijingDate = new Date(year, month - 1, day, hours, minutes, seconds);
      const weekdays = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
      const weekday = weekdays[beijingDate.getDay()];

      return { hours, minutes, seconds, year, month, day, weekday };
