            margin-top: 0.5rem;
        }

        @media (max-width: 700px) {
            .notes-grid {
                grid-template-columns: 1fr;
            }
            .form-grid {
                grid-template-columns: 1fr;
            }
            .stats-strip {
                gap: 1rem 1.5rem;
            }
        }

        /* note card */
        .note-card {
            background: white;
            border-radius: 1rem;
            padding: 1rem 1.2rem 1rem;
            border: 1px solid #e2e8f0;
            box-shadow: 0 2px 6px rgba(0,0,0,0.02);
            transition: 0.1s;
            word-wrap: break-word;
        }

        .note-card-header {
            display: flex;
            justify-content: space-between;
            align-items: flex-start;
            gap: 0.5rem;
        }

        .note-title {
            font-weight: 600;
            font-size: 1.1rem;
            color: #0f172a;
        }

        .badge {
            font-size: 0.65rem;
            font-weight: 600;
            padding: 0.15rem 0.7rem;
            border-radius: 40px;
            background: #e2e8f0;
            color: #1e293b;
            white-space: nowrap;
            letter-spacing: 0.02em;
        }
        .badge-action {
            background: #fee2e2;
            color: #991b1b;
        }
        .badge-decision {
            background: #dbeafe;
            color: #1e3a8a;
        }
        .badge-reference {
            background: #e2e8f0;
            color: #334155;
        }

        .note-meta {
            font-size: 0.8rem;
            color: #475569;
            margin: 0.4rem 0 0.2rem;
            display: flex;
            flex-wrap: wrap;
            gap: 0.4rem 1rem;
